from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    if aggregation_funcs is None:
        aggregation_funcs = {
            "count": lambda x: len(x),
            "avg_score": lambda x: sum(x["scores"]) / len(x["scores"]) if x["scores"] else 0,
            "max_score": lambda x: max(x["scores"]) if x["scores"] else 0,
            "min_score": lambda x: min(x["scores"]) if x["scores"] else 0
        }

    aggregated_data = defaultdict(lambda: {"scores": [], "count": 0})

    for result in search_results:
        metadata = result.metadata
        group_value = metadata.get(group_by_field)

        # Handle missing group field values
        if group_value is None or group_value == "":
            group_value = "unknown"

        # Accumulate data for aggregation
        aggregated_data[group_value]["scores"].append(result.score)
        aggregated_data[group_value]["count"] += 1

    # Compute final aggregated statistics
    aggregated_results = {}
    for group_value, data in aggregated_data.items():
        group_stats = {}
        # Apply default aggregation functions
        for stat_name, func in aggregation_funcs.items():
            try:
                group_stats[stat_name] = func(data)
            except Exception as e:
                group_stats[stat_name] = f"Error: {str(e)}"

        aggregated_results[group_value] = group_stats

    return aggregated_results

